}

.hero p {
  color: var(--muted);
  line-height: 1.6;
}

.stats {
  max-width: 1100px;
  margin: 1.5rem auto 0;
  padding: 0 1rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 0.8rem;
}

.stat-card {
  background: var(--card);
