  color: var(--text);
}

.member-form textarea {
  resize: vertical;
  min-height: 96px;
}

.avatar-manager {
  display: flex;
  align-items: center;
  gap: 0.65rem;
}

.avatar-preview {
  width: 64px;
  height: 64px;
  border-radius: 10px;
  border: 1px solid var(--border);
