}

.filter-row {
  margin-top: 0.7rem;
  display: grid;
  grid-template-columns: 1fr;
  gap: 0.6rem;
}

.member-grid {
  max-width: 1100px;
  margin: 0 auto 2rem;
  padding: 0 1rem;
  display: grid;
