.member-card {
  background: linear-gradient(155deg, #19191b 0%, #121214 100%);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 0;
  min-height: 312px;
  overflow: hidden;
  perspective: 1100px;
  transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
  cursor: pointer;
  position: relative;
