    radial-gradient(1200px 500px at 15% -10%, rgba(212, 175, 55, 0.12), transparent 58%),
    radial-gradient(900px 420px at 90% 0%, rgba(212, 175, 55, 0.06), transparent 62%),
    linear-gradient(140deg, #080808 0%, #0f0f10 46%, #111214 100%);
}

.ambient-bg {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: -1;
}

.ambient-bg__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(70px);
}

.ambient-bg__orb--one {
  width: 340px;
  height: 340px;
  left: -80px;
  top: 120px;
  background: rgba(212, 175, 55, 0.18);
}

.ambient-bg__orb--two {
  width: 280px;
  height: 280px;
  right: -80px;
  top: 220px;
  background: rgba(212, 175, 55, 0.11);
}

.ambient-bg__gear {
  position: absolute;
  border-radius: 50%;
  opacity: 0.22;
  border: 16px solid rgba(212, 175, 55, 0.18);
  background: repeating-conic-gradient(
    from 0deg,
    rgba(212, 175, 55, 0.42) 0deg 10deg,
    transparent 10deg 24deg
  );
  box-shadow: inset 0 0 0 10px rgba(15, 15, 16, 0.9), 0 0 0 1px rgba(212, 175, 55, 0.15);
  animation: gearSpin 40s linear infinite;
}

.ambient-bg__gear::before {
  content: '';
  position: absolute;
  inset: 30%;
  border-radius: 50%;
  background: rgba(212, 175, 55, 0.35);
}

.ambient-bg__gear--one {
  width: 240px;
  height: 240px;
  left: 6%;
  top: 62%;
}

.ambient-bg__gear--two {
  width: 190px;
  height: 190px;
  left: 21%;
  top: 71%;
  animation-direction: reverse;
  animation-duration: 54s;
}

.ambient-bg__gear--three {
  width: 300px;
  height: 300px;
  right: 4%;
  top: 56%;
  animation-duration: 62s;
}

.team-page .hero h1 {
  font-size: clamp(2.4rem, 5.4vw, 4.1rem);
  letter-spacing: 0.01em;
}

.team-page .hero p {
  max-width: 740px;
  font-size: 1.03rem;
}

.team-page .controls input,
.team-page .controls select {
  transition: border-color 0.28s var(--ease-premium), box-shadow 0.28s var(--ease-premium), transform 0.28s var(--ease-premium);
}

.team-page .controls input:focus,
.team-page .controls select:focus {
  outline: none;
  border-color: rgba(212, 175, 55, 0.58);
  box-shadow: 0 0 0 4px rgba(212, 175, 55, 0.1);
  transform: translateY(-1px);
}

.team-page .stat-card {
  background: linear-gradient(152deg, rgba(26, 26, 29, 0.92), rgba(13, 13, 16, 0.96));
  transition: transform 0.35s var(--ease-premium), border-color 0.35s var(--ease-premium), box-shadow 0.35s var(--ease-premium);
}

.team-page .stat-card:hover {
  transform: translateY(-4px);
  border-color: rgba(212, 175, 55, 0.45);
  box-shadow: 0 14px 30px rgba(0, 0, 0, 0.3);
}

.team-page .member-card {
  --stagger: 0ms;
  transition: transform 0.34s var(--ease-premium), box-shadow 0.34s var(--ease-premium), border-color 0.34s var(--ease-premium);
  animation: cardRise 0.58s var(--ease-premium) both;
  animation-delay: var(--stagger, 0ms);
}

.team-page .member-card:active {
  transform: scale(0.985);
}

.team-page .member-card.is-clicked {
  transform: scale(0.97);
}

.member-card__media {
  position: relative;
  border-radius: 12px;
  overflow: hidden;
  min-height: 196px;
}

.member-card__media::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.84) 12%, rgba(0, 0, 0, 0.44) 50%, rgba(0, 0, 0, 0.1) 72%, transparent 100%);
  pointer-events: none;
}

.team-page .avatar {
  margin-bottom: 0;
  border-radius: 0;
  height: 196px;
  transition: transform 0.52s var(--ease-premium);
}

.member-card__content {
  position: absolute;
  left: 0.8rem;
  right: 0.8rem;
  bottom: 0.8rem;
  z-index: 2;
  color: #fff;
  transform: translateY(12px);
  opacity: 0.72;
  transition: transform 0.34s var(--ease-premium), opacity 0.34s var(--ease-premium);
}

.member-card__content h3 {
  margin: 0;
  font-size: 1.08rem;
}

.member-card__role {
  margin: 0.2rem 0 0;
  color: rgba(255, 250, 236, 0.88);
  font-size: 0.9rem;
}

.team-page .member-card:hover {
  border-color: rgba(212, 175, 55, 0.5);
}

.team-page .member-card.is-hover-open,
.team-page .member-card:focus-within {
  transform: translateY(-9px) scale(1.03);
  z-index: 30;
  box-shadow: 0 18px 42px rgba(0, 0, 0, 0.42), 0 0 0 1px rgba(212, 175, 55, 0.22);
}

.team-page .member-card.is-hover-open .member-card__flip,
.team-page .member-card:focus-within .member-card__flip {
  transform: rotateY(180deg);
}

.team-page .member-card:hover .avatar {
  transform: scale(1.06);
}

.team-page .member-card:hover .member-card__content {
  transform: translateY(0);
  opacity: 1;
}

.team-page .member-card .post-pill {
  margin-top: 0.82rem;
}

.member-card__back-links {
  margin-top: 0;
}

.profile-modal {
  opacity: 1;
  transition: opacity 0.22s var(--ease-premium);
}

.profile-modal.hidden {
  opacity: 0;
}

.profile-modal__backdrop {
  transition: opacity 0.26s var(--ease-premium);
}

.profile-modal__dialog {
  padding: 1.2rem;
  gap: 1.2rem;
  background: linear-gradient(165deg, #0b0b0c 0%, #111114 100%);
  transition: transform 0.32s var(--ease-premium), opacity 0.32s var(--ease-premium);
}

.profile-modal__post {
  color: #f0cf70;
  font-weight: 600;
}

.profile-modal__content h2 {
  font-size: clamp(2rem, 5vw, 2.8rem);
}

.profile-modal__quote {
  font-family: Georgia, "Times New Roman", serif;
  font-size: clamp(1.06rem, 2.2vw, 1.24rem);
  font-style: italic;
  line-height: 1.8;
}

.skill-tag {
  transition: transform 0.2s var(--ease-premium), filter 0.2s var(--ease-premium);
}

.skill-tag:hover {
  transform: scale(1.05);
  filter: brightness(1.03);
}

@keyframes cardRise {
  from {
    opacity: 0;
    transform: translateY(18px) scale(0.99);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

@keyframes gearSpin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

body.admin-gated .navbar,
body.admin-gated .admin-layout,
body.admin-gated .toast {
  display: none;
}

@media (prefers-reduced-motion: reduce) {
  .team-page .member-card,
  .member-card__flip,
  .team-page .avatar,
  .ambient-bg__gear,
  .profile-modal,
  .profile-modal__dialog,
  .profile-modal__backdrop,
  .team-page .stat-card,
  .skill-tag,
  .team-page .controls input,
  .team-page .controls select {
    transition: none !important;
    animation: none !important;
  }
}

@media (max-width: 900px) {
  .admin-layout {
    grid-template-columns: 1fr;
  }

  .board-section__header {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.3rem;
  }

  .filter-row {
    grid-template-columns: 1fr;
  }

  .profile-modal__dialog {
    width: 100%;
    max-height: 92vh;
    padding: 1rem;
    gap: 0.9rem;
  }

  .member-card__media {
    min-height: 184px;
  }

  .team-page .avatar {
    height: 184px;
  }

  .team-page .member-card {
    animation-delay: 0ms;
  }
}

:root {
  --bg: #0f0f10;
  --card: #171719;
  --text: #f7f4ea;
  --muted: #bfb7a1;
  --gold: #d4af37;
  --gold-soft: #f3dc97;
  --border: #2c2c2f;
  --danger: #df5d5d;
  --ease-premium: cubic-bezier(0.22, 0.61, 0.36, 1);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "Segoe UI", Arial, sans-serif;
  background: radial-gradient(circle at top, #1a1a1d 0%, var(--bg) 58%);
  color: var(--text);
  min-height: 100vh;
}

body.modal-open {
  overflow: hidden;
}

.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid var(--border);
  background: rgba(15, 15, 16, 0.95);
  backdrop-filter: blur(4px);
  position: sticky;
  top: 0;
  z-index: 100;
}

.brand {
  color: var(--gold);
  font-weight: 700;
  letter-spacing: 0.06em;
}

.nav-links {
  display: flex;
  gap: 1rem;
}

.nav-links a {
  color: var(--text);
  text-decoration: none;
  padding: 0.45rem 0.8rem;
  border-radius: 999px;
  transition: 0.25s ease;
}

.nav-links a:hover,
.nav-links a.active {
  color: #121212;
  background: var(--gold);
}

.hero {
  max-width: 900px;
  margin: 2.5rem auto 0;
  padding: 0 1rem;
}

.eyebrow {
  color: var(--gold-soft);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  font-size: 0.82rem;
}

.hero h1 {
  margin: 0.4rem 0;
  font-size: clamp(2rem, 5vw, 3rem);
}

.hero p {
  color: var(--muted);
  line-height: 1.6;
}

.stats {
  max-width: 1100px;
  margin: 1.5rem auto 0;
  padding: 0 1rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 0.8rem;
}

.stat-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 1rem;
}

.stat-card .value {
  color: var(--gold);
  font-size: 1.4rem;
  font-weight: 700;
}

.stat-card .label {
  color: var(--muted);
  font-size: 0.86rem;
}

.controls {
  max-width: 1100px;
  margin: 1.2rem auto;
  padding: 0 1rem;
}

.controls input,
.controls select,
.member-form input,
.member-form textarea,
button {
  font: inherit;
}

.controls input,
.controls select,
.member-form input,
.member-form textarea {
  width: 100%;
  padding: 0.75rem;
  border-radius: 10px;
  border: 1px solid var(--border);
  background: #111113;
  color: var(--text);
}

.member-form textarea {
  resize: vertical;
  min-height: 96px;
}

.avatar-manager {
  display: flex;
  align-items: center;
  gap: 0.65rem;
}

.avatar-preview {
  width: 64px;
  height: 64px;
  border-radius: 10px;
  border: 1px solid var(--border);
  object-fit: cover;
}

.filter-row {
  margin-top: 0.7rem;
  display: grid;
  grid-template-columns: 1fr;
  gap: 0.6rem;
}

.member-grid {
  max-width: 1100px;
  margin: 0 auto 2rem;
  padding: 0 1rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
  gap: 1rem;
}

.member-grid.member-grid--sections {
  display: block;
}

.board-section {
  padding-top: 0.45rem;
}

.board-section + .board-section {
  margin-top: 1.25rem;
  padding-top: 1.5rem;
  border-top: 1px solid rgba(212, 175, 55, 0.28);
}

.board-section__header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 0.8rem;
  margin-bottom: 0.85rem;
}

.board-section__title {
  margin: 0;
  font-size: clamp(1.2rem, 2.2vw, 1.55rem);
  letter-spacing: 0.02em;
}

.board-section__count {
  margin: 0;
  color: var(--muted);
  font-size: 0.88rem;
}

.board-section__grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
  gap: 1rem;
}

.board-section--fe .board-section__title {
  color: #f3dc97;
}

.board-section--se .board-section__title {
  color: #e8c967;
}

.board-section--te .board-section__title {
  color: var(--gold);
}


.member-card {
  background: linear-gradient(155deg, #19191b 0%, #121214 100%);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 0;
  min-height: 312px;
  overflow: hidden;
  perspective: 1100px;
  transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
  cursor: pointer;
  position: relative;
  z-index: 1;
}

.member-card:hover {
  transform: translateY(-6px) scale(1.01);
  border-color: #8a752c;
  box-shadow: 0 14px 32px rgba(0, 0, 0, 0.35);
}

.member-card__flip {
  position: relative;
  width: 100%;
  min-height: 312px;
  transform-style: preserve-3d;
  transition: transform 0.56s var(--ease-premium);
}

.member-card__face {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  padding: 0.75rem;
  backface-visibility: hidden;
  border-radius: inherit;
}

.member-card__face--front {
  background: linear-gradient(155deg, #19191b 0%, #121214 100%);
}

.member-card__face--back {
  justify-content: center;
  gap: 0.9rem;
  background: linear-gradient(165deg, #121214 0%, #1b1b1f 100%);
  border: 1px solid rgba(212, 175, 55, 0.28);
  transform: rotateY(180deg);
}

.avatar {
  width: 100%;
  height: 200px;
  object-fit: cover;
  border-radius: 12px;
  margin-bottom: 0.8rem;
}

.member-card h3 {
  margin: 0.2rem 0;
}


.member-card__quote {
  margin: 0;
  color: var(--text);
  line-height: 1.55;
  font-style: italic;
  font-size: 0.96rem;
}

.member-card__badges {
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.member-card__badge {
  display: inline-flex;
  align-items: center;
  padding: 0.3rem 0.62rem;
  border-radius: 999px;
  border: 1px solid rgba(212, 175, 55, 0.35);
  color: var(--gold-soft);
  font-size: 0.78rem;
  font-weight: 600;
}

.member-card__no-contact {
  color: var(--muted);
  font-size: 0.9rem;
}

.meta {
  margin: 0.2rem 0;
  color: var(--muted);
}

.post-pill {
  display: inline-flex;
  margin: 0.4rem 0 0;
  padding: 0.35rem 0.7rem;
  border-radius: 999px;
  background: var(--gold);
  color: #111;
  font-size: 0.85rem;
  font-weight: 700;
}

.social-links {
  margin-top: 0.7rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.social-links a {
  color: var(--gold-soft);
  text-decoration: none;
}

.social-links a:hover {
  color: var(--gold);
}

.profile-modal {
  position: fixed;
  inset: 0;
  z-index: 2000;
  display: grid;
  place-items: center;
  padding: 1rem;
}

.profile-modal.hidden {
  display: none;
}

.profile-modal__backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.72);
  backdrop-filter: blur(10px);
}

.profile-modal__dialog {
  position: relative;
  width: min(92vw, 760px);
  max-height: min(90vh, 900px);
  overflow: auto;
  background: #0d0d0d;
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: 16px;
  box-shadow: 0 30px 70px rgba(0, 0, 0, 0.6);
  transform: scale(0.96);
  animation: modalIn 0.22s ease forwards;
  padding: 1rem;
  display: grid;
  gap: 1rem;
}

.profile-modal__close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  width: 2.25rem;
  height: 2.25rem;
  padding: 0;
  display: grid;
  place-items: center;
  line-height: 1;
  font-size: 1.35rem;
  font-weight: 500;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.05);
  color: var(--text);
}

.profile-modal__avatar {
  width: 100%;
  max-height: 340px;
  object-fit: cover;
  border-radius: 14px;
}

.profile-modal__content {
  display: grid;
  gap: 0.8rem;
}

.profile-modal__post {
  margin: 0;
  color: var(--gold-soft);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-size: 0.8rem;
}

.profile-modal__content h2 {
  margin: 0;
  font-size: clamp(1.8rem, 4vw, 2.4rem);
}

.profile-modal__meta {
  margin: 0;
  color: var(--muted);
}

.profile-modal__section h3 {
  margin: 0;
  color: var(--gold-soft);
  font-size: 0.95rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.profile-modal__text {
  margin: 0.45rem 0 0;
  color: var(--text);
  line-height: 1.65;
  white-space: pre-line;
}

.profile-badge-grid,
.profile-list-grid {
  margin-top: 0.5rem;
  display: grid;
  gap: 0.55rem;
}

.profile-badge-grid {
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
}

.profile-list-grid {
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
}

.profile-badge {
  display: inline-flex;
  align-items: center;
  padding: 0.38rem 0.72rem;
  border-radius: 999px;
  border: 1px solid rgba(212, 175, 55, 0.35);
  background: rgba(255, 255, 255, 0.03);
  color: var(--gold-soft);
  font-size: 0.82rem;
  font-weight: 600;
}

.profile-list-card {
  padding: 0.72rem 0.78rem;
  border-radius: 10px;
  border: 1px solid rgba(212, 175, 55, 0.2);
  background: rgba(255, 255, 255, 0.02);
  line-height: 1.5;
}

.profile-modal__quote {
  margin: 0;
  padding: 1rem 1.1rem;
  border-left: 4px solid var(--gold);
  background: rgba(255, 255, 255, 0.03);
  color: var(--text);
  border-radius: 10px;
  line-height: 1.7;
}

.profile-modal__work {
  margin: 0;
  color: var(--text);
  line-height: 1.65;
}

.skill-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.skill-tag {
  display: inline-flex;
  align-items: center;
  padding: 0.4rem 0.75rem;
  border-radius: 999px;
  background: var(--gold);
  color: #111;
  font-size: 0.82rem;
  font-weight: 700;
}

@keyframes modalIn {
  from {
    opacity: 0;
    transform: scale(0.94) translateY(10px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

.loading,
.empty {
  text-align: center;
  color: var(--muted);
  margin: 1rem auto;
}

.hidden {
  display: none !important;
}

.admin-layout {
  max-width: 1150px;
  margin: 1.5rem auto;
  display: grid;
  gap: 1rem;
  grid-template-columns: 1fr 1.2fr;
  padding: 0 1rem 2rem;
}

.admin-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1rem;
}

.admin-note {
  color: var(--muted);
  margin-top: 0;
}

.admin-auth {
  display: grid;
  gap: 0.55rem;
  margin-bottom: 1rem;
  padding: 1rem;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: #111113;
}

.auth-status {
  margin: 0;
  color: var(--muted);
  font-size: 0.92rem;
}

.auth-status.success {
  color: #a9e7b4;
}

.auth-status.error {
  color: #ff9c9c;
}

.member-form {
  display: grid;
  gap: 0.55rem;
  margin-top: 0.8rem;
}

.member-form.is-locked {
  opacity: 0.55;
  pointer-events: none;
  user-select: none;
}

.member-form label {
  font-size: 0.88rem;
  color: var(--gold-soft);
}

button {
  border: 1px solid transparent;
  border-radius: 10px;
  padding: 0.65rem 0.95rem;
  cursor: pointer;
  background: var(--gold);
  color: #1a1a1a;
  font-weight: 600;
  transition: 0.25s ease;
}

button:hover {
  transform: translateY(-1px);
  box-shadow: 0 8px 22px rgba(212, 175, 55, 0.27);
}

button.outline {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

button.danger {
  background: transparent;
  color: var(--danger);
  border-color: #723636;
}

.form-actions {
  display: flex;
  gap: 0.6rem;
  margin-top: 0.3rem;
}

.table-wrap {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th,
td {
  border-bottom: 1px solid var(--border);
  padding: 0.65rem 0.5rem;
  text-align: left;
}

td.actions {
  display: flex;
  gap: 0.5rem;
}

.toast {
  position: fixed;
  right: 1rem;
  bottom: 1rem;
  background: #1d1d1f;
  color: var(--text);
  border: 1px solid #404044;
  border-left: 4px solid var(--gold);
  padding: 0.8rem 1rem;
  border-radius: 10px;
  z-index: 999;
}

.toast.error {
  border-left-color: var(--danger);
}

.team-page {
  position: relative;
  background:
    radial-gradient(1200px 500px at 15% -10%, rgba(212, 175, 55, 0.12), transparent 58%),
    radial-gradient(900px 420px at 90% 0%, rgba(212, 175, 55, 0.06), transparent 62%),
    linear-gradient(140deg, #080808 0%, #0f0f10 46%, #111214 100%);
}

.ambient-bg {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: -1;
}

.ambient-bg__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(70px);
}

.ambient-bg__orb--one {
  width: 340px;
  height: 340px;
  left: -80px;
  top: 120px;
  background: rgba(212, 175, 55, 0.18);
}

.ambient-bg__orb--two {
  width: 280px;
  height: 280px;
  right: -80px;
  top: 220px;
  background: rgba(212, 175, 55, 0.11);
}

.ambient-bg__gear-img {
  position: absolute;
  opacity: 0.18;
  filter: drop-shadow(0 6px 20px rgba(212, 175, 55, 0.25));
  transform: translate3d(0, 0, 0) rotate(0deg);
  transform-origin: center;
  will-change: transform;
}

.ambient-bg__gear-img--one {
  width: 240px;
  height: 240px;
  left: 6%;
  top: 62%;
}

.ambient-bg__gear-img--two {
  width: 190px;
  height: 190px;
  left: 21%;
  top: 71%;
}

.ambient-bg__gear-img--three {
  width: 300px;
  height: 300px;
  right: 4%;
  top: 56%;
}

.team-page .hero h1 {
  font-size: clamp(2.4rem, 5.4vw, 4.1rem);
  letter-spacing: 0.01em;
}

.team-page .hero p {
  max-width: 740px;
  font-size: 1.03rem;
}

.team-page .controls input,
.team-page .controls select {
  transition: border-color 0.28s var(--ease-premium), box-shadow 0.28s var(--ease-premium), transform 0.28s var(--ease-premium);
}

.team-page .controls input:focus,
.team-page .controls select:focus {
  outline: none;
  border-color: rgba(212, 175, 55, 0.58);
  box-shadow: 0 0 0 4px rgba(212, 175, 55, 0.1);
  transform: translateY(-1px);
}

.team-page .stat-card {
  background: linear-gradient(152deg, rgba(26, 26, 29, 0.92), rgba(13, 13, 16, 0.96));
  transition: transform 0.35s var(--ease-premium), border-color 0.35s var(--ease-premium), box-shadow 0.35s var(--ease-premium);
}

.team-page .stat-card:hover {
  transform: translateY(-4px);
  border-color: rgba(212, 175, 55, 0.45);
  box-shadow: 0 14px 30px rgba(0, 0, 0, 0.3);
}

.team-page .member-card {
  --stagger: 0ms;
  transition: transform 0.34s var(--ease-premium), box-shadow 0.34s var(--ease-premium), border-color 0.34s var(--ease-premium);
  animation: cardRise 0.58s var(--ease-premium) both;
  animation-delay: var(--stagger, 0ms);
}

.team-page .member-card:active {
  transform: scale(0.985);
}

.team-page .member-card.is-clicked {
  transform: scale(0.97);
}

.member-card__media {
  position: relative;
  border-radius: 12px;
  overflow: hidden;
  min-height: 196px;
}

.member-card__media::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.84) 12%, rgba(0, 0, 0, 0.44) 50%, rgba(0, 0, 0, 0.1) 72%, transparent 100%);
  pointer-events: none;
}

.team-page .avatar {
  margin-bottom: 0;
  border-radius: 0;
  height: 196px;
  transition: transform 0.52s var(--ease-premium);
}

.member-card__content {
  position: absolute;
  left: 0.8rem;
  right: 0.8rem;
  bottom: 0.8rem;
  z-index: 2;
  color: #fff;
  transform: translateY(12px);
  opacity: 0.72;
  transition: transform 0.34s var(--ease-premium), opacity 0.34s var(--ease-premium);
}

.member-card__content h3 {
  margin: 0;
  font-size: 1.08rem;
}

.member-card__role {
  margin: 0.2rem 0 0;
  color: rgba(255, 250, 236, 0.88);
  font-size: 0.9rem;
}

.team-page .member-card:hover {
  border-color: rgba(212, 175, 55, 0.5);
}

.team-page .member-card.is-hover-open,
.team-page .member-card:focus-within {
  transform: translateY(-9px) scale(1.03);
  z-index: 30;
  box-shadow: 0 18px 42px rgba(0, 0, 0, 0.42), 0 0 0 1px rgba(212, 175, 55, 0.22);
}

.team-page .member-card.is-hover-open .member-card__flip,
.team-page .member-card:focus-within .member-card__flip {
  transform: rotateY(180deg);
}

.team-page .member-card:hover .avatar {
  transform: scale(1.06);
}

.team-page .member-card:hover .member-card__content {
  transform: translateY(0);
  opacity: 1;
}

.team-page .member-card .post-pill {
  margin-top: 0.82rem;
}

.member-card__back-links {
  margin-top: 0;
}

.profile-modal {
  opacity: 1;
  transition: opacity 0.22s var(--ease-premium);
}

.profile-modal.hidden {
  opacity: 0;
}

.profile-modal__backdrop {
  transition: opacity 0.26s var(--ease-premium);
}

.profile-modal__dialog {
  padding: 1.2rem;
  gap: 1.2rem;
  background: linear-gradient(165deg, #0b0b0c 0%, #111114 100%);
  transition: transform 0.32s var(--ease-premium), opacity 0.32s var(--ease-premium);
}

.profile-modal__post {
  color: #f0cf70;
  font-weight: 600;
}

.profile-modal__content h2 {
  font-size: clamp(2rem, 5vw, 2.8rem);
}

.profile-modal__quote {
  font-family: Georgia, "Times New Roman", serif;
  font-size: clamp(1.06rem, 2.2vw, 1.24rem);
  font-style: italic;
  line-height: 1.8;
}

.skill-tag {
  transition: transform 0.2s var(--ease-premium), filter 0.2s var(--ease-premium);
}

.skill-tag:hover {
  transform: scale(1.05);
  filter: brightness(1.03);
}

@keyframes cardRise {
  from {
    opacity: 0;
    transform: translateY(18px) scale(0.99);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

body.admin-gated .navbar,
body.admin-gated .admin-layout,
body.admin-gated .toast {
  display: none;
}

@media (prefers-reduced-motion: reduce) {
  .team-page .member-card,
  .member-card__flip,
  .team-page .avatar,
  .ambient-bg__gear-img,
  .profile-modal,
  .profile-modal__dialog,
  .profile-modal__backdrop,
  .team-page .stat-card,
  .skill-tag,
  .team-page .controls input,
  .team-page .controls select {
    transition: none !important;
    animation: none !important;
  }
}

@media (max-width: 900px) {
  .admin-layout {
    grid-template-columns: 1fr;
  }

  .board-section__header {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.3rem;
  }

  .filter-row {
    grid-template-columns: 1fr;
  }

  .profile-modal__dialog {
    width: 100%;
    max-height: 92vh;
    padding: 1rem;
    gap: 0.9rem;
  }

  .member-card__media {
    min-height: 184px;
  }

  .team-page .avatar {
    height: 184px;
  }

  .team-page .member-card {
    animation-delay: 0ms;
  }
}
